234	// drainServiceEventsWithRenderer drains the event stream and returns the
235	// aggregated final/routing/progress data. When wd is non-nil it activates
236	// three wedge-prevention mechanisms:
237	//
238	//  1. All-event idle reset: any received event resets the idle timer. The
239	//     timer fires only on complete silence (no events of any kind) within
240	//     the window.
241	//  2. Loop detection: identical (call, result) pairs that repeat ≥4 times in
242	//     an 8-entry window trigger wd.cancel.
243	//  3. Per-tool-call timeout: a tool_call without a matching tool_result within
244	//     wd.toolCallTimeout triggers wd.cancel.
245	func drainServiceEventsWithRenderer(events <-chan agentlib.ServiceEvent, w io.Writer, renderer WorkLogRenderer, wd *drainWatchdog, onRouteResolved func(harness, provider, model string)) (*agentlib.ServiceFinalData, *agentlib.ServiceRoutingDecisionData, []agentlib.ServiceProgressData) {
246		var final *agentlib.ServiceFinalData
247		var routing *agentlib.ServiceRoutingDecisionData
248		var progress []agentlib.ServiceProgressData
249	
250		// Fast path: no watchdog, simple range loop with no timer overhead.
251		if wd == nil || (wd.idleTimeout == 0 && wd.toolCallTimeout == 0) {
252			for ev := range events {
253				decoded, err := agentlib.DecodeServiceEvent(ev)
254				if err != nil {
255					continue
256				}
257				switch {
258				case decoded.RoutingDecision != nil:
259					routing = decoded.RoutingDecision
260					if onRouteResolved != nil {
261						onRouteResolved(routing.Harness, routing.Provider, routing.Model)
262					}
263					if w != nil {
264						if line := renderer.at(ev.Time).FormatRoutingDecision(decoded.RoutingDecision); line != "" {
265							_, _ = fmt.Fprint(w, line)
266						}
267					}
268				case decoded.Progress != nil:
269					progress = append(progress, *decoded.Progress)
270					if w != nil {
271						_, _ = fmt.Fprint(w, renderer.at(ev.Time).FormatServiceProgressEntries([]agentlib.ServiceProgressData{*decoded.Progress}))
272					}
273				case decoded.Final != nil:
274					final = decoded.Final
275				}
276			}
277			return final, routing, progress
278		}
279	
280		// Watchdog path: select loop so timers can fire alongside event reads.
281		ld := &loopDetector{}
282		var pendingCall *agentlib.ServiceToolCallData
283	
284		// resetIdle stops and restarts the idle timer. Only called on meaningful events.
285		var idleTimer *time.Timer
286		var idleTimerC <-chan time.Time
287		resetIdle := func() {
288			if wd.idleTimeout <= 0 {
289				return
290			}
291			if idleTimer == nil {
292				idleTimer = time.NewTimer(wd.idleTimeout)
293				idleTimerC = idleTimer.C
294				return
295			}
296			if !idleTimer.Stop() {
297				select {
298				case <-idleTimer.C:
299				default:
300				}
301			}
302			idleTimer.Reset(wd.idleTimeout)
303		}
304	
305		var toolCallTimer *time.Timer
306		var toolCallTimerC <-chan time.Time
307		startToolCallTimer := func() {
308			if wd.toolCallTimeout <= 0 {
309				return
310			}
311			if toolCallTimer == nil {
312				toolCallTimer = time.NewTimer(wd.toolCallTimeout)
313				toolCallTimerC = toolCallTimer.C
314				return
315			}
316			if !toolCallTimer.Stop() {
317				select {
318				case <-toolCallTimer.C:
319				default:
320				}
321			}
322			toolCallTimer.Reset(wd.toolCallTimeout)
323		}
324		stopToolCallTimer := func() {
325			if toolCallTimer == nil {
326				return
327			}
328			if !toolCallTimer.Stop() {
329				select {
330				case <-toolCallTimer.C:
331				default:
332				}
333			}
334			toolCallTimerC = nil
335		}
336	
337		// Arm the idle timer immediately so a session that never starts a tool
338		// call is still bounded.
339		if wd.idleTimeout > 0 {
340			idleTimer = time.NewTimer(wd.idleTimeout)
341			idleTimerC = idleTimer.C
342		}
343		defer func() {
344			if idleTimer != nil {
345				idleTimer.Stop()
346			}
347			if toolCallTimer != nil {
348				toolCallTimer.Stop()
349			}
350		}()
351	
352		for {
353			select {
354			case ev, ok := <-events:
355				if !ok {
356					return final, routing, progress
357				}
358				decoded, err := agentlib.DecodeServiceEvent(ev)
359				if err != nil {
360					continue
361				}
362				// Any received event resets the idle timer; only true silence fires it.
363				resetIdle()
364				switch {
365				case decoded.ToolCall != nil:
366					startToolCallTimer()
367					callCopy := *decoded.ToolCall
368					pendingCall = &callCopy
369	
370				case decoded.ToolResult != nil:
371					stopToolCallTimer()
372					if pendingCall != nil {
373						key := makeLoopKey(*pendingCall, *decoded.ToolResult)
374						if ld.record(key) {
375							_, _ = fmt.Fprintf(os.Stderr, "agent: loop detected (command=%q repeated ≥4 times): cancelling\n", pendingCall.Name)
376							if wd.cancel != nil {
377								wd.cancel()
378							}
379							return final, routing, progress
380						}
381						pendingCall = nil
382					}
383	
384				case decoded.Final != nil:
385					stopToolCallTimer()
386					final = decoded.Final
387	
388				case decoded.RoutingDecision != nil:
389					routing = decoded.RoutingDecision
390					if onRouteResolved != nil {
391						onRouteResolved(routing.Harness, routing.Provider, routing.Model)
392					}
393					if w != nil {
394						if line := renderer.at(ev.Time).FormatRoutingDecision(decoded.RoutingDecision); line != "" {
395							_, _ = fmt.Fprint(w, line)
396						}
397					}
398	
399				case decoded.Progress != nil:
400					progress = append(progress, *decoded.Progress)
401					if w != nil {
402						_, _ = fmt.Fprint(w, renderer.at(ev.Time).FormatServiceProgressEntries([]agentlib.ServiceProgressData{*decoded.Progress}))
403					}
404				}
405	
406			case <-idleTimerC:
407				_, _ = fmt.Fprintf(os.Stderr, "agent: idle timeout (%s without meaningful event): cancelling\n", wd.idleTimeout)
408				if wd.cancel != nil {
409					wd.cancel()
410				}
411				return final, routing, progress
412	
413			case <-toolCallTimerC:
414				name := ""
415				if pendingCall != nil {
416					name = pendingCall.Name
417				}
418				_, _ = fmt.Fprintf(os.Stderr, "agent: tool call timeout (%s, tool=%q): cancelling\n", wd.toolCallTimeout, name)
419				if wd.cancel != nil {
420					wd.cancel()
421				}
422				return final, routing, progress
423			}
424		}
425	}
426	
427	func selectedRoutingCandidateMetrics(routing *agentlib.ServiceRoutingDecisionData) (int, float64, float64, string) {
428		if routing == nil {
429			return 0, 0, 0, ""
430		}
431		for _, candidate := range routing.Candidates {
432			if candidate.Eligible && candidate.Model == routing.Model {
433				return candidate.Components.Power, candidate.Components.SpeedTPS, candidate.CostUSDPer1kTokens, candidate.CostSource
434			}
435		}
436		return 0, 0, 0, ""
437	}
