197	func writeWorkStatusJSON(out io.Writer, report WorkStatusReport) error {
198		if report.Workers == nil {
199			report.Workers = []workerstatus.LiveWorker{}
200		}
201		enc := json.NewEncoder(out)
202		enc.SetIndent("", "  ")
203		return enc.Encode(report)
204	}
