1	// Package workerstatus reports on live "ddx work" / "ddx try" processes,
2	// scoped to a specific project root by default.
3	//
4	// Operators and agents asking "is the worker still working beads?" must be
5	// able to answer the question for one project at a time. A global process
6	// scan ("ps aux | grep ddx work") returns workers from every checkout on the
7	// machine and produces a misleading "yes, working" signal when the worker
8	// belongs to a different repository. This package filters live workers by
9	// the resolved project root so the answer always matches the question.
10	package workerstatus
11	
12	import (
13		"context"
14		"path/filepath"
15		"regexp"
16		"strings"
17		"time"
18	)
19	
20	// LiveWorker describes one running ddx worker process.
21	type LiveWorker struct {
22		PID               int       `json:"pid"`
23		Command           string    `json:"command"`
24		StartedAt         time.Time `json:"started_at"`
25		AgeSeconds        float64   `json:"age_seconds"`
26		Age               string    `json:"age"`
27		ProjectRoot       string    `json:"project_root"`
28		BeadID            string    `json:"bead_id,omitempty"`
29		AttemptID         string    `json:"attempt_id,omitempty"`
30		Phase             string    `json:"phase,omitempty"`
31		Message           string    `json:"message,omitempty"`
32		ChildPID          int       `json:"child_pid,omitempty"`
33		LastActivityAt    time.Time `json:"last_activity_at,omitempty"`
34		ExecutionWorktree string    `json:"execution_worktree,omitempty"`
35		Cwd               string    `json:"cwd,omitempty"`
36	}
37	
38	// Scanner discovers live ddx worker processes on the host.
39	type Scanner interface {
40		Scan(ctx context.Context) ([]LiveWorker, error)
41	}
42	
43	// New returns the platform-appropriate Scanner. On Linux this reads /proc.
44	// On other platforms it returns an empty list; the caller's tests and the
45	// --all-projects escape hatch remain meaningful regardless.
46	func New() Scanner {
47		return newSystemScanner()
48	}
49	
50	// beadIDPattern matches ddx-style bead identifiers (prefix + hex, 8+ chars
51	// total) embedded in argv strings or worktree paths.
52	var beadIDPattern = regexp.MustCompile(`\bddx-[a-f0-9]{8}\b`)
53	
54	// executionWorktreePattern matches the conventional execute-bead worktree
55	// directory name (`.execute-bead-wt-<bead>-<timestamp>-<suffix>`) anywhere
56	// in a path. The directory name is enough to identify the worktree even when
57	// the surrounding path is unconventional.
58	var executionWorktreePattern = regexp.MustCompile(`(?:^|/)(\.execute-bead-wt-[^/]+)`)
59	
60	// InferBead extracts a bead ID and execution worktree path from the worker's
61	// command line and current working directory. It returns the longest worktree
62	// path that contains a `.execute-bead-wt-*` segment (typically the cwd, when
63	// the inline worker has chdir'd into the isolated worktree), and the first
64	// bead ID matched in either the command line or the worktree path.
65	//
66	// Either return value may be empty when no signal is present, which is the
67	// expected case for a long-running `ddx work` drain that has not yet started
68	// a specific bead.
69	func InferBead(cmdline, cwd string) (beadID, worktree string) {
70		worktree = extractWorktreePath(cwd)
71		if worktree == "" {
72			worktree = extractWorktreePath(cmdline)
73		}
74	
75		if m := beadIDPattern.FindString(worktree); m != "" {
76			beadID = m
77		}
78		if beadID == "" {
79			if m := beadIDPattern.FindString(cmdline); m != "" {
80				beadID = m
81			}
82		}
83		if beadID == "" {
84			if m := beadIDPattern.FindString(cwd); m != "" {
85				beadID = m
86			}
87		}
88		return beadID, worktree
89	}
90	
91	func extractWorktreePath(s string) string {
92		if s == "" {
93			return ""
94		}
95		if !strings.Contains(s, ".execute-bead-wt-") {
96			return ""
97		}
98		matches := executionWorktreePattern.FindStringIndex(s)
99		if matches == nil {
100			return ""
101		}
102		start := matches[0]
103		end := matches[1]
104		for start > 0 {
105			r := s[start-1]
106			if r == ' ' || r == '\x00' || r == '\t' {
107				break
108			}
109			start--
110		}
111		for end < len(s) {
112			r := s[end]
113			if r == ' ' || r == '\x00' || r == '\t' {
114				break
115			}
116			end++
117		}
118		return s[start:end]
119	}
120	
121	// FilterByProject returns workers whose ProjectRoot resolves to the same path
122	// as projectRoot. Resolution canonicalises both sides via filepath.Abs and
123	// filepath.EvalSymlinks so a symlinked checkout matches its real path.
124	func FilterByProject(workers []LiveWorker, projectRoot string) []LiveWorker {
125		target := canonicalPath(projectRoot)
126		out := make([]LiveWorker, 0, len(workers))
127		for _, w := range workers {
128			if SamePath(w.ProjectRoot, target) {
129				out = append(out, w)
130			}
131		}
132		return out
133	}
134	
135	// SamePath reports whether a and b refer to the same on-disk location after
136	// canonicalisation. It tolerates empty inputs (returning false) so callers
137	// can safely compare optional fields without prefiltering.
138	func SamePath(a, b string) bool {
139		ca := canonicalPath(a)
140		cb := canonicalPath(b)
141		if ca == "" || cb == "" {
142			return false
143		}
144		return ca == cb
145	}
146	
147	func canonicalPath(p string) string {
148		if strings.TrimSpace(p) == "" {
149			return ""
150		}
151		abs, err := filepath.Abs(p)
152		if err != nil {
153			abs = filepath.Clean(p)
154		}
155		if resolved, err := filepath.EvalSymlinks(abs); err == nil {
156			return resolved
157		}
158		return abs
159	}
160	
161	// FormatAge renders a duration as a short human-readable string mirroring
162	// the conventions used by the server-backed worker list (`5s`, `12m`,
163	// `1h30m`). It is intended for terminal output; JSON output uses
164	// AgeSeconds as the numeric source of truth.
165	func FormatAge(d time.Duration) string {
166		if d < time.Minute {
167			if d < 0 {
168				d = 0
169			}
170			return roundedSeconds(d)
171		}
172		if d < time.Hour {
173			return roundedMinutes(d)
174		}
175		hours := int(d.Hours())
176		mins := int(d.Minutes()) % 60
177		if mins == 0 {
178			return durationHours(hours)
179		}
180		return durationHoursMinutes(hours, mins)
181	}
182	
183	func roundedSeconds(d time.Duration) string {
184		secs := int(d.Seconds())
185		return durationSeconds(secs)
186	}
187	
188	func roundedMinutes(d time.Duration) string {
189		mins := int(d.Minutes())
190		return durationMinutes(mins)
191	}
192	
193	func durationSeconds(n int) string { return formatUnit(n, "s") }
194	func durationMinutes(n int) string { return formatUnit(n, "m") }
195	func durationHours(n int) string   { return formatUnit(n, "h") }
196	func durationHoursMinutes(h, m int) string {
197		return formatUnit(h, "h") + formatUnit(m, "m")
198	}
199	
200	func formatUnit(n int, unit string) string {
201		if n < 0 {
202			n = 0
203		}
204		return itoa(n) + unit
205	}
206	
207	func itoa(n int) string {
208		if n == 0 {
209			return "0"
210		}
211		neg := n < 0
212		if neg {
213			n = -n
214		}
215		var digits [20]byte
216		i := len(digits)
217		for n > 0 {
218			i--
219			digits[i] = byte('0' + n%10)
220			n /= 10
221		}
222		out := string(digits[i:])
223		if neg {
224			return "-" + out
225		}
226		return out
227	}
