17	// RunStateFileName is the basename of the live run-state file, relative to
18	// the project's .ddx directory.
19	const RunStateFileName = "run-state.json"
20	
21	// RunStateDirName is the .ddx subdirectory containing per-attempt live-state
22	// records. The legacy .ddx/run-state.json file remains as a compatibility
23	// summary view for older operators.
24	const RunStateDirName = "run-state"
25	
26	// RunStateLivenessTTL is the default expiry window written to refreshed
27	// attempt liveness records.
28	const RunStateLivenessTTL = 2 * time.Minute
29	
30	// RunState is the on-disk record of an executing bead attempt. It is written at
31	// execute-bead start, refreshed while the agent runs, and removed on completion
32	// (or on orphan recovery of a crashed worker). Operators and HELIX consume this
33	// state to observe what is running without polling the bead tracker.
34	//
35	// See CONTRACT-001 §5 (Always-on runtime metrics and provenance).
36	type RunState struct {
37		BeadID       string    `json:"bead_id"`
38		AttemptID    string    `json:"attempt_id"`
39		Harness      string    `json:"harness,omitempty"`
40		Model        string    `json:"model,omitempty"`
41		StartedAt    time.Time `json:"started_at"`
42		WorktreePath string    `json:"worktree_path"`
43		PID          int       `json:"pid,omitempty"`
44		SessionID    string    `json:"session_id,omitempty"`
45		RefreshedAt  time.Time `json:"refreshed_at,omitempty"`
46		ExpiresAt    time.Time `json:"expires_at,omitempty"`
47		// Candidate-cycle fields mirror cleanup metadata so operators can see
48		// which candidate phase owns a long-lived attempt worktree.
49		CandidateCyclePhase string `json:"candidate_cycle_phase,omitempty"`
50		CandidateRef        string `json:"candidate_ref,omitempty"`
51		CandidateRev        string `json:"candidate_rev,omitempty"`
52		CycleIndex          int    `json:"cycle_index,omitempty"`
53		ReviewActive        bool   `json:"review_active,omitempty"`
54		RepairActive        bool   `json:"repair_active,omitempty"`
55	}
56	
57	// runStatePath returns the absolute path of the run-state file for the
58	// project rooted at projectRoot.
59	func runStatePath(projectRoot string) string {
60		return filepath.Join(beadStoreRoot(projectRoot), RunStateFileName)
61	}
62	
63	func runStateDirPath(projectRoot string) string {
64		return filepath.Join(beadStoreRoot(projectRoot), RunStateDirName)
65	}
66	
67	func existingRunStatePath(projectRoot string) (string, bool) {
68		root, ok := existingBeadStoreRoot(projectRoot)
69		if !ok {
70			return "", false
71		}
72		path := filepath.Join(root, RunStateFileName)
73		if _, err := os.Stat(path); err == nil {
74			return path, true
75		}
76		return "", false
77	}
78	
79	func existingRunStateDirPath(projectRoot string) (string, bool) {
80		root, ok := existingBeadStoreRoot(projectRoot)
81		if !ok {
82			return "", false
83		}
84		path := filepath.Join(root, RunStateDirName)
85		if info, err := os.Stat(path); err == nil && info.IsDir() {
86			return path, true
87		}
88		return "", false
89	}
90	
91	func existingBeadStoreRoot(projectRoot string) (string, bool) {
92		if projectRoot == "" {
93			return "", false
94		}
95		inTree := filepath.Join(projectRoot, ddxroot.DirName)
96		if info, err := os.Stat(inTree); err == nil && info.IsDir() {
97			return inTree, true
98		}
99		if root, ok := ddxroot.ExistingPath(context.Background(), projectRoot); ok {
100			return root, true
101		}
102		return "", false
103	}
104	
105	func runStateAttemptPath(projectRoot, attemptID string) (string, error) {
106		name, err := runStateAttemptFileName(attemptID)
107		if err != nil {
108			return "", err
109		}
110		return filepath.Join(runStateDirPath(projectRoot), name), nil
111	}
112	
113	func runStateAttemptFileName(attemptID string) (string, error) {
114		attemptID = strings.TrimSpace(attemptID)
115		if attemptID == "" {
116			return "", errors.New("run-state: attempt_id is empty")
117		}
118		if filepath.Base(attemptID) != attemptID || strings.ContainsAny(attemptID, `/\`) {
119			return "", fmt.Errorf("run-state: invalid attempt_id %q", attemptID)
120		}
121		return attemptID + ".json", nil
122	}
123	
124	func normalizeRunState(state RunState) RunState {
125		now := time.Now().UTC()
126		if state.StartedAt.IsZero() {
127			state.StartedAt = now
128		}
129		if state.RefreshedAt.IsZero() {
130			state.RefreshedAt = now
131		}
132		if state.ExpiresAt.IsZero() {
133			state.ExpiresAt = state.RefreshedAt.Add(RunStateLivenessTTL)
134		}
135		if state.PID == 0 {
136			state.PID = os.Getpid()
137		}
138		return state
139	}
140	
141	// WriteRunState atomically writes state to a per-attempt file under
142	// .ddx/run-state/ and refreshes .ddx/run-state.json as a legacy compatibility
143	// summary. Writes go to sibling tmp files and are then renamed into place so
144	// readers never observe a partial record.
145	func WriteRunState(projectRoot string, state RunState) error {
146		if projectRoot == "" {
147			return errors.New("WriteRunState: projectRoot is empty")
148		}
149		state = normalizeRunState(state)
150		attemptPath, err := runStateAttemptPath(projectRoot, state.AttemptID)
151		if err != nil {
152			return err
153		}
154		ddxDir := beadStoreRoot(projectRoot)
155		attemptDir := filepath.Dir(attemptPath)
156		if err := os.MkdirAll(ddxDir, 0o755); err != nil {
157			return fmt.Errorf("run-state: mkdir .ddx: %w", err)
158		}
159		if err := os.MkdirAll(attemptDir, 0o755); err != nil {
160			return fmt.Errorf("run-state: mkdir attempts: %w", err)
161		}
162		if err := writeRunStateJSON(attemptPath, state); err != nil {
163			return err
164		}
165		return writeRunStateJSON(runStatePath(projectRoot), state)
166	}
167	
168	func writeRunStateJSON(final string, state RunState) error {
169		dir := filepath.Dir(final)
170		if err := os.MkdirAll(dir, 0o755); err != nil {
171			return fmt.Errorf("run-state: mkdir: %w", err)
172		}
173		data, err := json.MarshalIndent(state, "", "  ")
174		if err != nil {
175			return fmt.Errorf("run-state: marshal: %w", err)
176		}
177		data = append(data, '\n')
178	
179		tmp, err := os.CreateTemp(dir, "run-state-*.json.tmp")
180		if err != nil {
181			return fmt.Errorf("run-state: create tmp: %w", err)
182		}
183		tmpName := tmp.Name()
184		if _, err := tmp.Write(data); err != nil {
185			_ = tmp.Close()
186			_ = os.Remove(tmpName)
187			return fmt.Errorf("run-state: write tmp: %w", err)
188		}
189		if err := tmp.Close(); err != nil {
190			_ = os.Remove(tmpName)
191			return fmt.Errorf("run-state: close tmp: %w", err)
192		}
193		if err := os.Rename(tmpName, final); err != nil {
194			_ = os.Remove(tmpName)
195			return fmt.Errorf("run-state: rename: %w", err)
196		}
197		return nil
198	}
199	
200	// ReadRunState returns a compatibility live-state summary for projectRoot, or
201	// (nil, nil) when no live attempt exists. A malformed compatibility file
202	// surfaces as an error; if the compatibility file is missing, the newest
203	// per-attempt record is returned.
204	func ReadRunState(projectRoot string) (*RunState, error) {
205		path, ok := existingRunStatePath(projectRoot)
206		if !ok {
207			return nil, nil
208		}
209		state, err := readRunStateFile(path)
210		if err != nil {
211			if !os.IsNotExist(err) {
212				return nil, err
213			}
214			states, statesErr := readRunStateAttemptFiles(projectRoot)
215			if statesErr != nil {
216				return nil, statesErr
217			}
218			if latest, ok := latestRunState(states); ok {
219				return &latest, nil
220			}
221			return nil, nil
222		}
223		return state, nil
224	}
225	
226	func readRunStateFile(path string) (*RunState, error) {
227		data, err := os.ReadFile(path)
228		if err != nil {
229			if os.IsNotExist(err) {
230				return nil, err
231			}
232			return nil, err
233		}
234		var s RunState
235		if err := json.Unmarshal(data, &s); err != nil {
236			return nil, fmt.Errorf("run-state: parse: %w", err)
237		}
238		return &s, nil
239	}
240	
241	// ReadRunStates returns all live attempt records. The per-attempt directory is
242	// authoritative; when it is absent or empty, this falls back to the legacy
243	// compatibility file so older on-disk state can still be recovered.
244	func ReadRunStates(projectRoot string) ([]RunState, error) {
245		states, err := readRunStateAttemptFiles(projectRoot)
246		if err != nil {
247			return nil, err
248		}
249		if len(states) > 0 {
250			return states, nil
251		}
252		path, ok := existingRunStatePath(projectRoot)
253		if !ok {
254			return nil, nil
255		}
256		state, err := readRunStateFile(path)
257		if err != nil {
258			if os.IsNotExist(err) {
259				return nil, nil
260			}
261			return nil, err
262		}
263		if state == nil {
264			return nil, nil
265		}
266		return []RunState{*state}, nil
267	}
268	
269	func readRunStateAttemptFiles(projectRoot string) ([]RunState, error) {
270		dir, ok := existingRunStateDirPath(projectRoot)
271		if !ok {
272			return nil, nil
273		}
274		entries, err := os.ReadDir(dir)
275		if err != nil {
276			if os.IsNotExist(err) {
277				return nil, nil
278			}
279			return nil, err
280		}
281		var names []string
282		for _, entry := range entries {
283			if entry.IsDir() {
284				continue
285			}
286			name := entry.Name()
287			if !strings.HasSuffix(name, ".json") || strings.HasSuffix(name, ".tmp") {
288				continue
289			}
290			names = append(names, name)
291		}
292		sort.Strings(names)
293	
294		states := make([]RunState, 0, len(names))
295		for _, name := range names {
296			state, err := readRunStateFile(filepath.Join(dir, name))
297			if err != nil {
298				return nil, err
299			}
300			if state != nil {
301				states = append(states, *state)
302			}
303		}
304		return states, nil
305	}
306	
307	func latestRunState(states []RunState) (RunState, bool) {
308		if len(states) == 0 {
309			return RunState{}, false
310		}
311		latest := states[0]
312		for _, state := range states[1:] {
313			if runStateNewer(state, latest) {
314				latest = state
315			}
316		}
317		return latest, true
318	}
319	
320	func runStateNewer(a, b RunState) bool {
321		if !a.RefreshedAt.Equal(b.RefreshedAt) {
322			return a.RefreshedAt.After(b.RefreshedAt)
323		}
324		if !a.StartedAt.Equal(b.StartedAt) {
325			return a.StartedAt.After(b.StartedAt)
326		}
327		return a.AttemptID > b.AttemptID
328	}
329	
330	// ClearRunState removes all run-state records, including the compatibility
331	// summary and per-attempt files. A missing file or directory is not an error.
332	func ClearRunState(projectRoot string) error {
333		err := os.Remove(runStatePath(projectRoot))
334		if err != nil && !os.IsNotExist(err) {
335			return err
336		}
337		entries, err := os.ReadDir(runStateDirPath(projectRoot))
338		if err != nil {
339			if os.IsNotExist(err) {
340				return nil
341			}
342			return err
343		}
344		for _, entry := range entries {
345			if entry.IsDir() {
346				continue
347			}
348			if err := os.Remove(filepath.Join(runStateDirPath(projectRoot), entry.Name())); err != nil && !os.IsNotExist(err) {
349				return err
350			}
351		}
352		return nil
353	}
354	
355	// ClearRunStateAttempt removes one attempt record and refreshes the legacy
356	// compatibility summary from the newest remaining attempt. Other live attempts
357	// are preserved.
358	func ClearRunStateAttempt(projectRoot, attemptID string) error {
359		attemptPath, err := runStateAttemptPath(projectRoot, attemptID)
360		if err != nil {
361			return err
362		}
363		if err := os.Remove(attemptPath); err != nil && !os.IsNotExist(err) {
364			return err
365		}
366		states, err := readRunStateAttemptFiles(projectRoot)
367		if err != nil {
368			return err
369		}
370		if latest, ok := latestRunState(states); ok {
371			return writeRunStateJSON(runStatePath(projectRoot), latest)
372		}
373		err = os.Remove(runStatePath(projectRoot))
374		if err != nil && !os.IsNotExist(err) {
375			return err
376		}
377		return nil
378	}
