107	// ListLiveness reads every status.json sidecar under projectRoot's worker
108	// directory. Malformed sidecars are skipped silently — the sidecar is
109	// best-effort observability, not authoritative state.
110	func ListLiveness(projectRoot string) ([]LivenessRecord, error) {
111		dir := LivenessDir(projectRoot)
112		entries, err := os.ReadDir(dir)
113		if err != nil {
114			if os.IsNotExist(err) {
115				return nil, nil
116			}
117			return nil, err
118		}
119		var out []LivenessRecord
120		for _, entry := range entries {
121			if !entry.IsDir() {
122				continue
123			}
124			rec, err := ReadLiveness(projectRoot, entry.Name())
125			if err != nil {
126				continue
127			}
128			out = append(out, rec)
129		}
130		sort.Slice(out, func(i, j int) bool {
131			return out[i].LastActivityAt.After(out[j].LastActivityAt)
132		})
133		return out, nil
134	}
135	
136	// IsFresh reports whether rec.LastActivityAt is within LivenessTTL of now.
137	func (r LivenessRecord) IsFresh(now time.Time) bool {
138		if r.LastActivityAt.IsZero() {
139			return false
140		}
141		return now.Sub(r.LastActivityAt) <= LivenessTTL
142	}
