14	// MarkResultExecutionError preserves a populated worker result as a structured
15	// attempt failure. Callers use this when ExecuteBeadWithConfig returned both a
16	// result and an error; the presence of the result means DDx has enough
17	// execution context to report the attempt instead of aborting the process.
18	func MarkResultExecutionError(res *ExecuteBeadResult, err error) {
19		if res == nil || err == nil {
20			return
21		}
22		if res.Outcome == "" {
23			res.Outcome = ExecuteBeadOutcomeTaskFailed
24		}
25		if res.Reason == "" {
26			res.Reason = err.Error()
27		}
28		if res.Error == "" {
29			res.Error = err.Error()
30		}
31		if res.Status == "" || res.Status == ExecuteBeadStatusNoChanges {
32			res.Status = ClassifyExecuteBeadStatus("error", res.ExitCode, res.Reason)
33		}
34		res.Detail = ExecuteBeadStatusDetail(res.Status, res.Reason, res.Error)
35		res.FailureMode = ClassifyFailureMode(res.Outcome, res.ExitCode, res.Error)
36		if res.FailureMode == "" {
37			res.FailureMode = FailureModeUnknown
38		}
39		// A pre-dispatch provider-boundary failure carries its typed classification
40		// on the error (ddx-3b721804). Prefer it so the report's outcome_reason is
41		// the precise provider taxonomy (provider_auth, provider_model_unavailable,
42		// ...) rather than the coarse worker-level bucket.
43		var pfErr *ProviderFailureError
44		if errors.As(err, &pfErr) && pfErr.Failure.Reason != "" {
45			res.FailureMode = pfErr.Failure.Reason
46		}
47	}
