49	// MarkResultLandError records a coordinator/landing failure on a completed
50	// worker result. When possible it first pins ResultRev under refs/ddx/iterations
51	// so the worker's commit remains reachable even though the target branch did
52	// not advance cleanly.
53	func MarkResultLandError(projectRoot string, res *ExecuteBeadResult, err error) {
54		if res == nil || err == nil {
55			return
56		}
57		if markReconciledAlreadyLanded(projectRoot, res, err) {
58			return
59		}
60		reason := "land coordination failed: " + err.Error()
61		if action, ok := classifyLandCoordinationAction(err.Error()); ok {
62			switch action {
63			case landCoordinationActionRetryLand:
64				reason = "land coordination retry: " + err.Error()
65				preserveResultRefForLandError(projectRoot, res, &reason)
66				res.Outcome = "land_coordination_retry"
67				res.Reason = reason
68				res.Error = err.Error()
69				res.Status = ExecuteBeadStatusLandRetry
70				res.OrchestratorStatus = res.Status
71				res.Detail = ExecuteBeadStatusDetail(res.Status, res.Reason, res.Error)
72				res.FailureMode = FailureModeLandRetry
73				return
74			case landCoordinationActionOperatorAttention:
75				reason = "land coordination operator attention: " + err.Error()
76				preserveResultRefForLandError(projectRoot, res, &reason)
77				res.Outcome = "land_coordination_operator_attention"
78				res.Reason = reason
79				res.Error = err.Error()
80				res.Status = ExecuteBeadStatusLandOperatorAttention
81				res.OrchestratorStatus = res.Status
82				res.Detail = ExecuteBeadStatusDetail(res.Status, res.Reason, res.Error)
83				res.FailureMode = FailureModeLandOperatorAttention
84				return
85			}
86		}
87		preserveResultRefForLandError(projectRoot, res, &reason)
88		res.Outcome = "error"
89		res.Reason = reason
90		res.Error = err.Error()
91		res.Status = ClassifyExecuteBeadStatus(res.Outcome, res.ExitCode, res.Reason)
92		res.OrchestratorStatus = res.Status
93		res.Detail = ExecuteBeadStatusDetail(res.Status, res.Reason, res.Error)
94		res.FailureMode = classifyLandingFailureMode(res.Outcome, res.Reason, res.GateResults, res.FailureMode)
95	}
