97	func preserveResultRefForLandError(projectRoot string, res *ExecuteBeadResult, reason *string) {
98		if res == nil || res.ResultRev == "" || res.ResultRev == res.BaseRev {
99			return
100		}
101		preserveRef := landIterationRef(res.BeadID, res.AttemptID, res.BaseRev)
102		if upErr := (RealLandingGitOps{}).UpdateRefTo(projectRoot, preserveRef, res.ResultRev, ""); upErr == nil {
103			res.PreserveRef = preserveRef
104		} else if reason != nil {
105			*reason = fmt.Sprintf("%s; preserving result failed: %v", *reason, upErr)
106		}
107	}
