116	func markReconciledAlreadyLanded(projectRoot string, res *ExecuteBeadResult, err error) bool {
117		if projectRoot == "" || res == nil || res.ResultRev == "" || res.ResultRev == res.BaseRev || err == nil {
118			return false
119		}
120		if !strings.Contains(strings.ToLower(err.Error()), "cannot lock ref") {
121			return false
122		}
123		targets := landCoordinationTargetRefs(err.Error())
124		targets = append(targets, "HEAD")
125		for _, target := range targets {
126			tip, ok := resultReachableFromRef(projectRoot, res.ResultRev, target)
127			if !ok {
128				continue
129			}
130			if res.ImplementationRev == "" {
131				res.ImplementationRev = res.ResultRev
132			}
133			res.ResultRev = tip
134			res.LandedRev = tip
135			res.Outcome = "merged"
136			res.Reason = "land coordination reconciled: result already landed"
137			res.Error = err.Error()
138			res.Status = ExecuteBeadStatusSuccess
139			res.OrchestratorStatus = res.Status
140			res.Detail = ExecuteBeadStatusDetail(res.Status, res.Reason, res.Error)
141			res.FailureMode = ""
142			return true
143		}
144		return false
145	}
