147	func resultReachableFromRef(projectRoot, resultRev, ref string) (string, bool) {
148		tipOut, err := internalgit.Command(context.Background(), projectRoot, "rev-parse", "--verify", ref).Output()
149		if err != nil {
150			return "", false
151		}
152		tip := strings.TrimSpace(string(tipOut))
153		if tip == "" {
154			return "", false
155		}
156		err = internalgit.Command(context.Background(), projectRoot, "merge-base", "--is-ancestor", resultRev, tip).Run()
157		return tip, err == nil
158	}
