160	func landCoordinationTargetRefs(msg string) []string {
161		var refs []string
162		for _, token := range strings.FieldsFunc(msg, func(r rune) bool {
163			return r == '\'' || r == '"' || r == ':' || r == ' ' || r == '\n' || r == '\t'
164		}) {
165			token = strings.TrimSpace(token)
166			if strings.HasPrefix(token, "refs/heads/") {
167				refs = append(refs, token)
168			}
169		}
170		return refs
171	}
172	
173	func classifyLandCoordinationAction(msg string) (landCoordinationAction, bool) {
174		lower := strings.ToLower(msg)
175		if strings.Contains(lower, "staged changes after waiting") {
176			paths := stagedPathsFromLandError(msg)
177			if len(paths) > 0 && allGeneratedLandCoordinationPaths(paths) {
178				return landCoordinationActionRetryLand, true
179			}
180			return landCoordinationActionOperatorAttention, true
181		}
182		if strings.Contains(lower, "cannot lock ref") {
183			return landCoordinationActionRetryLand, true
184		}
185		return "", false
186	}
187	
188	func stagedPathsFromLandError(msg string) []string {
189		lines := strings.Split(msg, "\n")
190		if len(lines) <= 1 {
191			return nil
192		}
193		var paths []string
194		for _, line := range lines[1:] {
195			line = strings.TrimSpace(line)
196			if line == "" {
197				continue
198			}
199			if tab := strings.IndexByte(line, '\t'); tab >= 0 {
200				line = line[tab+1:]
201			}
202			if p := strings.TrimSpace(line); p != "" {
203				paths = append(paths, filepath.ToSlash(p))
204			}
205		}
206		return paths
207	}
208	
209	func allGeneratedLandCoordinationPaths(paths []string) bool {
210		for _, p := range paths {
211			if trackerpaths.IsManagedTrackerPath(p) ||
212				strings.HasPrefix(p, ".ddx/executions/") ||
213				strings.HasPrefix(p, ".ddx/runs/") ||
214				strings.HasPrefix(p, ".ddx/metrics/") ||
215				strings.HasPrefix(p, ".ddx/attachments/") {
216				continue
217			}
218			return false
219		}
220		return true
221	}
