1	//go:build !windows
2	
3	package agent
4	
5	import (
6		"bytes"
7		"context"
8		"fmt"
9		"os"
10		"os/exec"
11		"path/filepath"
12		"sort"
13		"strconv"
14		"strings"
15		"syscall"
16		"time"
17	)
18	
19	const attemptProcessCleanupArtifact = "process-cleanup.json"
20	
21	type attemptProcessSnapshot struct {
22		PIDs map[int]struct{}
23		Err  string
24	}
25	
26	type attemptProcessInfo struct {
27		PID     int    `json:"pid"`
28		PPID    int    `json:"ppid"`
29		PGID    int    `json:"pgid,omitempty"`
30		Cwd     string `json:"cwd,omitempty"`
31		Command string `json:"command,omitempty"`
32	}
33	
34	type attemptProcessCleanupReport struct {
35		AttemptID   string               `json:"attempt_id"`
36		BeadID      string               `json:"bead_id"`
37		Worktree    string               `json:"worktree"`
38		Trigger     string               `json:"trigger"`
39		StartedAt   time.Time            `json:"started_at"`
40		FinishedAt  time.Time            `json:"finished_at"`
41		Scanned     int                  `json:"scanned"`
42		Candidates  []attemptProcessInfo `json:"candidates,omitempty"`
43		Killed      []attemptProcessInfo `json:"killed,omitempty"`
44		StillAlive  []attemptProcessInfo `json:"still_alive,omitempty"`
45		BaselineErr string               `json:"baseline_error,omitempty"`
46		ScanErr     string               `json:"scan_error,omitempty"`
47		KillErrors  []string             `json:"kill_errors,omitempty"`
48	}
49	
50	func captureAttemptProcessBaseline(ctx context.Context, worktree string) attemptProcessSnapshot {
51		processes, err := scanAttemptProcesses(ctx)
52		if err != nil {
53			return attemptProcessSnapshot{PIDs: map[int]struct{}{}, Err: err.Error()}
54		}
55		pids := make(map[int]struct{}, len(processes))
56		for _, proc := range attemptCleanupCandidates(processes, nil, worktree) {
57			pids[proc.PID] = struct{}{}
58		}
59		return attemptProcessSnapshot{PIDs: pids}
60	}
61	
62	func cleanupAttemptProcesses(ctx context.Context, projectRoot, beadID, attemptID, worktree string, baseline attemptProcessSnapshot, trigger string) *attemptProcessCleanupReport {
63		started := time.Now().UTC()
64		report := &attemptProcessCleanupReport{
65			AttemptID:   attemptID,
66			BeadID:      beadID,
67			Worktree:    worktree,
68			Trigger:     trigger,
69			StartedAt:   started,
70			BaselineErr: baseline.Err,
71		}
72		processes, err := scanAttemptProcesses(context.Background())
73		if err != nil {
74			report.ScanErr = err.Error()
75			report.FinishedAt = time.Now().UTC()
76			writeAttemptProcessCleanupArtifact(projectRoot, attemptID, report)
77			return report
78		}
79		report.Scanned = len(processes)
80		candidates := attemptCleanupCandidates(processes, baseline.PIDs, worktree)
81		report.Candidates = candidates
82		if len(candidates) == 0 && trigger == "" && baseline.Err == "" {
83			return nil
84		}
85	
86		killAttemptProcesses(candidates, report)
87	
88		after, scanErr := scanAttemptProcesses(context.Background())
89		if scanErr != nil {
90			report.ScanErr = strings.TrimSpace(strings.Join([]string{report.ScanErr, scanErr.Error()}, "\n"))
91		} else {
92			live := map[int]attemptProcessInfo{}
93			for _, proc := range after {
94				live[proc.PID] = proc
95			}
96			for _, proc := range candidates {
97				if current, ok := live[proc.PID]; ok && signalProcessAlive(proc.PID) {
98					report.StillAlive = append(report.StillAlive, current)
99				} else {
100					report.Killed = append(report.Killed, proc)
101				}
102			}
103		}
104		report.FinishedAt = time.Now().UTC()
105		writeAttemptProcessCleanupArtifact(projectRoot, attemptID, report)
106		return report
107	}
108	
109	func writeAttemptProcessCleanupArtifact(projectRoot, attemptID string, report *attemptProcessCleanupReport) {
110		if report == nil || strings.TrimSpace(projectRoot) == "" || strings.TrimSpace(attemptID) == "" {
111			return
112		}
113		path := filepath.Join(projectRoot, ExecuteBeadArtifactDir, attemptID, attemptProcessCleanupArtifact)
114		_ = writeArtifactJSON(path, report)
115	}
116	
117	func attemptCleanupCandidates(processes []attemptProcessInfo, baseline map[int]struct{}, worktree string) []attemptProcessInfo {
118		self := os.Getpid()
119		out := make([]attemptProcessInfo, 0)
120		for _, proc := range processes {
121			if proc.PID <= 0 || proc.PID == self {
122				continue
123			}
124			if baseline != nil {
125				if _, seen := baseline[proc.PID]; seen {
126					continue
127				}
128			}
129			if processCwdWithin(proc.Cwd, worktree) || processCommandMentionsAttempt(proc.Command, worktree) {
130				out = append(out, proc)
131			}
132		}
133		sort.Slice(out, func(i, j int) bool {
134			di := processDepth(processes, out[i].PID)
135			dj := processDepth(processes, out[j].PID)
136			if di == dj {
137				return out[i].PID > out[j].PID
138			}
139			return di > dj
140		})
141		return out
142	}
143	
144	func processDepth(processes []attemptProcessInfo, pid int) int {
145		parent := map[int]int{}
146		for _, proc := range processes {
147			parent[proc.PID] = proc.PPID
148		}
149		depth := 0
150		for pid > 0 {
151			ppid := parent[pid]
152			if ppid <= 0 || ppid == pid {
153				return depth
154			}
155			depth++
156			pid = ppid
157		}
158		return depth
159	}
160	
161	func processCommandMentionsAttempt(command, worktree string) bool {
162		if strings.TrimSpace(command) == "" || strings.TrimSpace(worktree) == "" {
163			return false
164		}
165		return strings.Contains(command, worktree) || strings.Contains(command, filepath.Base(worktree))
166	}
167	
168	func processCwdWithin(cwd, root string) bool {
169		if strings.TrimSpace(cwd) == "" || strings.TrimSpace(root) == "" {
170			return false
171		}
172		cleanCwd := canonicalCleanupPath(cwd)
173		cleanRoot := canonicalCleanupPath(root)
174		return cleanCwd == cleanRoot || strings.HasPrefix(cleanCwd, cleanRoot+string(filepath.Separator))
175	}
176	
177	func canonicalCleanupPath(path string) string {
178		abs, err := filepath.Abs(path)
179		if err != nil {
180			abs = filepath.Clean(path)
181		}
182		if real, err := filepath.EvalSymlinks(abs); err == nil {
183			abs = real
184		}
185		return filepath.Clean(abs)
186	}
187	
188	func killAttemptProcesses(candidates []attemptProcessInfo, report *attemptProcessCleanupReport) {
189		for _, proc := range candidates {
190			if proc.PID <= 0 || proc.PID == os.Getpid() {
191				continue
192			}
193			if err := syscall.Kill(proc.PID, syscall.SIGTERM); err != nil && err != syscall.ESRCH {
194				report.KillErrors = append(report.KillErrors, fmt.Sprintf("SIGTERM pid %d: %v", proc.PID, err))
195			}
196		}
197		deadline := time.Now().Add(750 * time.Millisecond)
198		for time.Now().Before(deadline) {
199			allGone := true
200			for _, proc := range candidates {
201				if signalProcessAlive(proc.PID) {
202					allGone = false
203					break
204				}
205			}
206			if allGone {
207				return
208			}
209			time.Sleep(25 * time.Millisecond)
210		}
211		for _, proc := range candidates {
212			if !signalProcessAlive(proc.PID) {
213				continue
214			}
215			if err := syscall.Kill(proc.PID, syscall.SIGKILL); err != nil && err != syscall.ESRCH {
216				report.KillErrors = append(report.KillErrors, fmt.Sprintf("SIGKILL pid %d: %v", proc.PID, err))
217			}
218		}
219	}
220	
221	func signalProcessAlive(pid int) bool {
222		if pid <= 0 {
223			return false
224		}
225		return syscall.Kill(pid, 0) == nil
226	}
227	
228	func scanAttemptProcesses(ctx context.Context) ([]attemptProcessInfo, error) {
229		cmd := exec.CommandContext(ctx, "ps", "-axo", "pid=,ppid=,pgid=,command=")
230		out, err := cmd.Output()
231		if err != nil {
232			return nil, err
233		}
234		processes := parseAttemptPS(out)
235		for i := range processes {
236			processes[i].Cwd = readProcessCwd(processes[i].PID)
237		}
238		return processes, nil
239	}
240	
241	func parseAttemptPS(out []byte) []attemptProcessInfo {
242		lines := bytes.Split(out, []byte{'\n'})
243		processes := make([]attemptProcessInfo, 0, len(lines))
244		for _, line := range lines {
245			fields := strings.Fields(string(line))
246			if len(fields) < 3 {
247				continue
248			}
249			pid, pidErr := strconv.Atoi(fields[0])
250			ppid, ppidErr := strconv.Atoi(fields[1])
251			pgid, pgidErr := strconv.Atoi(fields[2])
252			if pidErr != nil || ppidErr != nil || pgidErr != nil {
253				continue
254			}
255			cmdline := ""
256			if len(fields) > 3 {
257				cmdline = strings.Join(fields[3:], " ")
258			}
259			processes = append(processes, attemptProcessInfo{
260				PID:     pid,
261				PPID:    ppid,
262				PGID:    pgid,
263				Command: cmdline,
264			})
265		}
266		return processes
267	}
268	
269	func readProcessCwd(pid int) string {
270		if pid <= 0 {
271			return ""
272		}
273		if cwd, err := os.Readlink(filepath.Join("/proc", strconv.Itoa(pid), "cwd")); err == nil {
274			return cwd
275		}
276		return ""
277	}
