19	type orphanHarnessProcess struct {
20		PID     int
21		PPID    int
22		Command string
23		Cwd     string
24	}
25	
26	type orphanHarnessProcessScanner interface {
27		Scan(context.Context) ([]orphanHarnessProcess, error)
28	}
29	
30	type orphanHarnessLeaseReader interface {
31		ClaimLease(id string) (bead.ClaimLeaseRecord, bool, error)
32	}
33	
34	type orphanHarnessLeaseReleaser interface {
35		Release(id, assignee, targetStatus string) error
36	}
37	
38	type orphanHarnessEventAppender interface {
39		AppendEvent(id string, event bead.BeadEvent) error
40	}
41	
42	// reapOrphanedHarnessChildren kills orphaned harness subprocesses that still
43	// sit inside this project's execution worktree root and clears the stale lease
44	// they were holding.
45	func reapOrphanedHarnessChildren(
46		ctx context.Context,
47		projectRoot string,
48		scanner orphanHarnessProcessScanner,
49		leaseReader orphanHarnessLeaseReader,
50		releaser orphanHarnessLeaseReleaser,
51		appender orphanHarnessEventAppender,
52		assignee string,
53		log io.Writer,
54		emit func(string, map[string]any),
55		killGroup func(int) error,
56	) (int, error) {
57		if ctx != nil && ctx.Err() != nil {
58			return 0, ctx.Err()
59		}
60		if scanner == nil || projectRoot == "" {
61			return 0, nil
62		}
63		if killGroup == nil {
64			killGroup = func(int) error { return nil }
65		}
66	
67		processes, err := scanner.Scan(ctx)
68		if err != nil {
69			return 0, err
70		}
71	
72		execRoot := canonicalExecRoot(config.ExecutionTempRoot(projectRoot))
73		if execRoot == "" {
74			return 0, nil
75		}
76	
77		reaped := 0
78		for _, proc := range processes {
79			if ctx != nil && ctx.Err() != nil {
80				return reaped, ctx.Err()
81			}
82			if proc.PPID != 1 || proc.PID <= 0 {
83				continue
84			}
85			if !looksLikeHarnessProcess(proc.Command) {
86				continue
87			}
88			beadID, worktree := workerstatus.InferBead(proc.Command, proc.Cwd)
89			if beadID == "" || worktree == "" {
90				continue
91			}
92			if !isWithinProjectExecutionRoot(execRoot, worktree) {
93				continue
94			}
95			if leaseReader == nil {
96				continue
97			}
98			lease, found, leaseErr := leaseReader.ClaimLease(beadID)
99			if leaseErr != nil || !found || lease.PID <= 0 || processAlive(lease.PID) {
100				continue
101			}
102	
103			diagnosis := fmt.Sprintf(
104				"orphaned harness child %d (parent pid 1) in %s; claim owner pid %d is gone",
105				proc.PID, worktree, lease.PID,
106			)
107	
108			if killErr := killGroup(proc.PID); killErr != nil && log != nil {
109				_, _ = fmt.Fprintf(log, "startup orphan reaper: failed to kill process group %d for %s: %v\n", proc.PID, beadID, killErr)
110			}
111			if releaser != nil {
112				_ = releaser.Release(beadID, assignee, "")
113			}
114			if appender != nil {
115				body, _ := json.Marshal(map[string]any{
116					"reason":             "orphaned_harness_child",
117					"bead_id":            beadID,
118					"process_pid":        proc.PID,
119					"process_parent_pid": proc.PPID,
120					"claim_owner_pid":    lease.PID,
121					"worktree":           worktree,
122					"project_root":       projectRoot,
123					"diagnosis":          diagnosis,
124				})
125				_ = appender.AppendEvent(beadID, bead.BeadEvent{
126					Kind:      "operator_attention",
127					Summary:   "orphaned_harness_child",
128					Body:      string(body),
129					Actor:     assignee,
130					Source:    "ddx work",
131					CreatedAt: time.Now().UTC(),
132				})
133			}
134			if emit != nil {
135				emit("loop.operator_attention", map[string]any{
136					"reason":             "orphaned_harness_child",
137					"bead_id":            beadID,
138					"process_pid":        proc.PID,
139					"process_parent_pid": proc.PPID,
140					"claim_owner_pid":    lease.PID,
141					"worktree":           worktree,
142					"project_root":       projectRoot,
143					"diagnosis":          diagnosis,
144				})
145			}
146			if log != nil {
147				_, _ = fmt.Fprintf(log, "startup orphan reaper: reaped orphaned harness child %d for %s\n", proc.PID, beadID)
148			}
149			reaped++
150		}
151	
152		return reaped, nil
153	}
154	
155	func looksLikeHarnessProcess(cmdline string) bool {
156		if strings.TrimSpace(cmdline) == "" {
157			return false
158		}
159		parts := strings.Fields(cmdline)
160		if len(parts) == 0 {
161			return false
162		}
163		switch filepath.Base(parts[0]) {
164		case "claude", "codex", "gemini", "opencode", "pi":
165			return true
166		default:
167			return false
168		}
169	}
170	
171	func canonicalExecRoot(path string) string {
172		if strings.TrimSpace(path) == "" {
173			return ""
174		}
175		abs, err := filepath.Abs(path)
176		if err != nil {
177			abs = filepath.Clean(path)
178		}
179		if real, err := filepath.EvalSymlinks(abs); err == nil {
180			abs = real
181		}
182		return filepath.Clean(abs)
183	}
184	
185	func isWithinProjectExecutionRoot(execRoot, worktree string) bool {
186		if execRoot == "" || worktree == "" {
187			return false
188		}
189		abs := canonicalExecRoot(worktree)
190		if abs == execRoot {
191			return true
192		}
193		prefix := execRoot + string(filepath.Separator)
194		return strings.HasPrefix(abs, prefix)
195	}
196	
197	func processAlive(pid int) bool {
198		if pid <= 0 {
199			return false
200		}
201		proc, err := os.FindProcess(pid)
202		if err != nil {
203			return false
204		}
205		return proc.Signal(syscall.Signal(0)) == nil
206	}
