3	package agent
4	
5	import (
6		"bytes"
7		"context"
8		"fmt"
9		"os"
10		"path/filepath"
11		"strconv"
12		"strings"
13		"syscall"
14	)
15	
16	type procOrphanHarnessScanner struct{}
17	
18	func newOrphanHarnessProcessScanner() orphanHarnessProcessScanner {
19		return procOrphanHarnessScanner{}
20	}
21	
22	func (procOrphanHarnessScanner) Scan(ctx context.Context) ([]orphanHarnessProcess, error) {
23		entries, err := os.ReadDir("/proc")
24		if err != nil {
25			return nil, fmt.Errorf("read /proc: %w", err)
26		}
27		out := make([]orphanHarnessProcess, 0)
28		for _, entry := range entries {
29			if ctx != nil && ctx.Err() != nil {
30				return nil, ctx.Err()
31			}
32			if !entry.IsDir() {
33				continue
34			}
35			pid, err := strconv.Atoi(entry.Name())
36			if err != nil || pid <= 0 {
37				continue
38			}
39			proc, ok := inspectOrphanHarnessProcess(pid)
40			if !ok {
41				continue
42			}
43			out = append(out, proc)
44		}
45		return out, nil
46	}
47	
48	func inspectOrphanHarnessProcess(pid int) (orphanHarnessProcess, bool) {
49		base := filepath.Join("/proc", strconv.Itoa(pid))
50		cmdlineRaw, err := os.ReadFile(filepath.Join(base, "cmdline"))
51		if err != nil {
52			return orphanHarnessProcess{}, false
53		}
54		cmdline := decodeOrphanHarnessCmdline(cmdlineRaw)
55		if cmdline == "" {
56			return orphanHarnessProcess{}, false
57		}
58		cwd, _ := os.Readlink(filepath.Join(base, "cwd"))
59		ppid, ok := readOrphanHarnessParentPID(filepath.Join(base, "stat"))
60		if !ok {
61			return orphanHarnessProcess{}, false
62		}
63		return orphanHarnessProcess{
64			PID:     pid,
65			PPID:    ppid,
66			Command: cmdline,
67			Cwd:     cwd,
68		}, true
69	}
70	
71	func decodeOrphanHarnessCmdline(raw []byte) string {
72		if len(raw) == 0 {
73			return ""
74		}
75		if raw[len(raw)-1] == 0 {
76			raw = raw[:len(raw)-1]
77		}
78		parts := bytes.Split(raw, []byte{0})
79		out := make([]string, 0, len(parts))
80		for _, p := range parts {
81			if len(p) == 0 {
82				continue
83			}
84			out = append(out, string(p))
85		}
86		return strings.Join(out, " ")
87	}
88	
89	func readOrphanHarnessParentPID(statPath string) (int, bool) {
90		data, err := os.ReadFile(statPath)
91		if err != nil {
92			return 0, false
93		}
94		close := strings.LastIndex(string(data), ")")
95		if close < 0 {
96			return 0, false
97		}
98		tail := strings.Fields(string(data[close+1:]))
99		if len(tail) < 2 {
100			return 0, false
101		}
102		ppid, err := strconv.Atoi(tail[1])
103		if err != nil {
104			return 0, false
105		}
106		return ppid, true
107	}
108	
109	func killProcessGroup(pid int) error {
110		if pid <= 0 {
111			return nil
112		}
113		return syscall.Kill(-pid, syscall.SIGKILL)
114	}
