18	// newWorkStatusCommand creates the "ddx work status" subcommand: a
19	// project-scoped live-worker report.
20	//
21	// The default report lists only live `ddx work` / `ddx try` processes whose
22	// resolved project root matches the requested project. The earlier failure
23	// mode this command exists to prevent is a global `ps | grep ddx work` scan
24	// surfacing a worker from another repository while operators are asking
25	// about a specific project's queue.
26	func (f *CommandFactory) newWorkStatusCommand() *cobra.Command {
27		cmd := &cobra.Command{
28			Use:   "status",
29			Short: "Show live ddx workers scoped to this project",
30			Long: `status lists the live ddx worker processes (ddx work / ddx try)
31	whose project root matches the current project. The default scope is the
32	git root of the working directory; pass --project to override or
33	--all-projects to inspect every worker on the host.
34	
35	Workers from other repositories are intentionally excluded from the
36	default view. Reporting them as evidence that "the worker is still
37	running" hides whether the requested project's queue has stalled.
38	
39	Output columns (terminal):
40	  PID         — process id of the worker
41	  AGE         — wall-clock age since the worker process started
42	  COMMAND     — the worker's command line (truncated for terminals)
43	  BEAD        — active bead id when it can be inferred from argv or the
44	                isolated execute-bead worktree
45	  ATTEMPT     — active attempt id when a fresh worker liveness sidecar
46	                records one for the live worker
47	  WORKTREE    — execute-bead worktree path when the worker is inside one
48	
49	JSON output preserves the full set of fields including project_root,
50	attempt_id, phase, child_pid, and last_activity_at when available.`,
51			Example: `  # Show live workers for the current project
52	  ddx work status
53	
54	  # JSON for piping to jq
55	  ddx work status --json
56	
57	  # Explicit cross-project view
58	  ddx work status --all-projects --json`,
59			Args: cobra.NoArgs,
60			RunE: f.runWorkStatus,
61		}
62		cmd.Flags().String("project", "", "Target project root path (default: CWD git root). Env: DDX_PROJECT_ROOT")
63		cmd.Flags().Bool("all-projects", false, "Report workers from every project; opt-in escape hatch")
64		cmd.Flags().Bool("json", false, "Output as JSON")
65		return cmd
66	}
67	
68	// workerStatusScanner is set by tests via the CommandFactory to inject a
69	// deterministic worker set without spawning real processes.
70	type workerStatusScanner = workerstatus.Scanner
71	
72	// WorkStatusReport is the JSON payload emitted by `ddx work status --json`.
73	type WorkStatusReport struct {
74		ProjectRoot string                    `json:"project_root,omitempty"`
75		Scope       string                    `json:"scope"`
76		Workers     []workerstatus.LiveWorker `json:"workers"`
77		ActiveWork  activework.Snapshot       `json:"active_work"`
78	}
79	
80	func (f *CommandFactory) runWorkStatus(cmd *cobra.Command, _ []string) error {
81		projectFlag, _ := cmd.Flags().GetString("project")
82		allProjects, _ := cmd.Flags().GetBool("all-projects")
83		asJSON, _ := cmd.Flags().GetBool("json")
84	
85		projectRoot := resolveProjectRoot(projectFlag, f.WorkingDir)
86	
87		scanner := f.workerScanner()
88		all, err := scanner.Scan(cmd.Context())
89		if err != nil {
90			return fmt.Errorf("scan live workers: %w", err)
91		}
92	
93		now := time.Now().UTC()
94		report := WorkStatusReport{
95			ProjectRoot: projectRoot,
96			Scope:       "project",
97			Workers: enrichWorkersWithRunState(
98				workerstatus.EnrichWithFreshLiveness(filterAndSortWorkers(all, projectRoot, allProjects), now),
99				now,
100			),
101		}
102		if active, err := collectActiveWorkSnapshot(projectRoot, bead.NewStore(resolveBeadStoreRoot(projectRoot)), now); err == nil {
103			report.ActiveWork = active
104		} else {
105			return fmt.Errorf("work status: active work query: %w", err)
106		}
107		if allProjects {
108			report.Scope = "all-projects"
109		}
110	
111		out := cmd.OutOrStdout()
112		if asJSON {
113			return writeWorkStatusJSON(out, report)
114		}
115		writeWorkStatusText(out, report)
116		return nil
117	}
118	
119	func (f *CommandFactory) workerScanner() workerStatusScanner {
120		if f.workerScannerOverride != nil {
121			return f.workerScannerOverride
122		}
123		return workerstatus.New()
124	}
125	
126	// enrichWorkersWithRunState fills bead/attempt/worktree from a fresh
127	// per-attempt run-state record (.ddx/run-state/<attempt>.json) whose PID
128	// matches a live worker, when liveness enrichment did not supply them — e.g.
129	// the liveness sidecar was absent, start-time-skewed, or its attempt id was
130	// stale (ddx-f9b41107). Run-state is read from each worker's own project root,
131	// so all-projects scope does not leak attempts across projects.
132	func enrichWorkersWithRunState(workers []workerstatus.LiveWorker, now time.Time) []workerstatus.LiveWorker {
133		byProject := make(map[string][]agent.RunState)
134		for i := range workers {
135			w := &workers[i]
136			if w.PID <= 0 || (w.BeadID != "" && w.AttemptID != "" && w.ExecutionWorktree != "") {
137				continue
138			}
139			states, ok := byProject[w.ProjectRoot]
140			if !ok {
141				states, _ = agent.ReadRunStates(w.ProjectRoot)
142				byProject[w.ProjectRoot] = states
143			}
144			rec, ok := freshestRunStateForPID(states, w.PID, now)
145			if !ok {
146				continue
147			}
148			if w.BeadID == "" {
149				w.BeadID = rec.BeadID
150			}
151			if w.AttemptID == "" {
152				w.AttemptID = rec.AttemptID
153			}
154			if w.ExecutionWorktree == "" {
155				w.ExecutionWorktree = rec.WorktreePath
156			}
157		}
158		return workers
159	}
160	
161	// freshestRunStateForPID returns the most recently refreshed non-expired
162	// run-state record for pid, if any.
163	func freshestRunStateForPID(states []agent.RunState, pid int, now time.Time) (agent.RunState, bool) {
164		var best agent.RunState
165		found := false
166		for _, s := range states {
167			if s.PID != pid {
168				continue
169			}
170			if !s.ExpiresAt.IsZero() && now.After(s.ExpiresAt) {
171				continue
172			}
173			if !found || s.RefreshedAt.After(best.RefreshedAt) {
174				best = s
175				found = true
176			}
177		}
178		return best, found
179	}
180	
181	func filterAndSortWorkers(all []workerstatus.LiveWorker, projectRoot string, allProjects bool) []workerstatus.LiveWorker {
182		var filtered []workerstatus.LiveWorker
183		if allProjects {
184			filtered = append(filtered, all...)
185		} else {
186			filtered = workerstatus.FilterByProject(all, projectRoot)
187		}
188		sort.SliceStable(filtered, func(i, j int) bool {
189			if filtered[i].StartedAt.Equal(filtered[j].StartedAt) {
190				return filtered[i].PID < filtered[j].PID
191			}
192			return filtered[i].StartedAt.Before(filtered[j].StartedAt)
193		})
194		return filtered
195	}
