206	func writeWorkStatusText(out io.Writer, report WorkStatusReport) {
207		if report.ActiveWork.Count > 0 {
208			fmt.Fprintf(out, "active work for %s: %d bead(s)\n", report.ProjectRoot, report.ActiveWork.Count)
209			if len(report.ActiveWork.BeadIDs) > 0 {
210				fmt.Fprintf(out, "  beads: %s\n", strings.Join(report.ActiveWork.BeadIDs, ", "))
211			}
212		} else {
213			fmt.Fprintf(out, "active work for %s: 0 bead(s)\n", report.ProjectRoot)
214		}
215		if len(report.Workers) == 0 {
216			if report.Scope == "all-projects" {
217				fmt.Fprintln(out, "No live ddx workers found on this host.")
218				return
219			}
220			fmt.Fprintf(out, "No live ddx workers for project %s.\n", report.ProjectRoot)
221			return
222		}
223		if report.Scope == "all-projects" {
224			fmt.Fprintf(out, "live ddx workers (all projects): %d\n", len(report.Workers))
225		} else {
226			fmt.Fprintf(out, "live ddx workers for %s: %d\n", report.ProjectRoot, len(report.Workers))
227		}
228		for _, w := range report.Workers {
229			bead := w.BeadID
230			if bead == "" {
231				bead = "-"
232			}
233			attempt := w.AttemptID
234			if attempt == "" {
235				attempt = "-"
236			}
237			worktree := w.ExecutionWorktree
238			if worktree == "" {
239				worktree = "-"
240			}
241			line := fmt.Sprintf("  pid=%d age=%s project=%s bead=%s attempt=%s worktree=%s",
242				w.PID, w.Age, w.ProjectRoot, bead, attempt, worktree)
243			if w.Phase != "" {
244				line += fmt.Sprintf(" phase=%s", w.Phase)
245			}
246			if w.Message != "" {
247				line += fmt.Sprintf(" message=%q", w.Message)
248			}
249			fmt.Fprintf(out, "%s\n    %s\n", line, w.Command)
250		}
