2	
3	import (
4		"encoding/json"
5		"fmt"
6		"os"
7		"path/filepath"
8		"sort"
9		"time"
10	
11		"github.com/DocumentDrivenDX/ddx/internal/ddxroot"
12	)
13	
14	// LivenessRecord is the worker-side sidecar written under
15	// .ddx/workers/<worker-id>/status.json to mirror live progress of a
16	// long-running ddx work / ddx try attempt without rewriting beads.jsonl.
17	//
18	// The bead tracker remains the durable claim marker; this sidecar carries
19	// the high-frequency liveness signal so operators can answer "is the worker
20	// alive and what is it doing?" without inflating tracker churn.
21	type LivenessRecord struct {
22		WorkerID       string    `json:"worker_id"`
23		ProjectRoot    string    `json:"project_root,omitempty"`
24		CurrentBead    string    `json:"current_bead,omitempty"`
25		AttemptID      string    `json:"attempt_id,omitempty"`
26		Phase          string    `json:"phase,omitempty"`
27		Message        string    `json:"message,omitempty"`
28		Route          string    `json:"route,omitempty"`
29		Harness        string    `json:"harness,omitempty"`
30		Model          string    `json:"model,omitempty"`
31		Profile        string    `json:"profile,omitempty"`
32		PID            int       `json:"pid,omitempty"`
33		ChildPID       int       `json:"child_pid,omitempty"`
34		StartedAt      time.Time `json:"started_at,omitempty"`
35		LastActivityAt time.Time `json:"last_activity_at"`
36	}
37	
38	// LivenessTTL is the freshness window for treating a worker sidecar as
39	// "active". Defaults to 3× the bead tracker heartbeat interval (which is
40	// 30s) so a sidecar that has not been touched in ~90s is treated as stale.
41	var LivenessTTL = 90 * time.Second
42	
43	// LivenessDir returns the worker sidecar directory for a project.
44	func LivenessDir(projectRoot string) string {
45		inTree := ddxroot.InTree(projectRoot)
46		if info, err := os.Stat(inTree); err == nil && info.IsDir() {
47			return filepath.Join(inTree, "workers")
48		}
49		return ddxroot.JoinProject(projectRoot, "workers")
50	}
51	
52	// LivenessPath returns the status.json path for a worker under projectRoot.
53	func LivenessPath(projectRoot, workerID string) string {
54		return filepath.Join(LivenessDir(projectRoot), workerID, "status.json")
55	}
56	
57	// WriteLiveness writes rec to .ddx/workers/<workerID>/status.json using a
58	// tmp-then-rename so concurrent readers never see a half-written file.
59	func WriteLiveness(projectRoot, workerID string, rec LivenessRecord) error {
60		if projectRoot == "" || workerID == "" {
61			return fmt.Errorf("workerstatus: project root and worker id required")
62		}
63		dir := filepath.Join(LivenessDir(projectRoot), workerID)
64		if err := os.MkdirAll(dir, 0o755); err != nil {
65			return fmt.Errorf("workerstatus: mkdir worker dir: %w", err)
66		}
67		data, err := json.MarshalIndent(rec, "", "  ")
68		if err != nil {
69			return fmt.Errorf("workerstatus: marshal liveness: %w", err)
70		}
71		data = append(data, '\n')
72		final := filepath.Join(dir, "status.json")
73		tmp, err := os.CreateTemp(dir, "status-*.tmp")
74		if err != nil {
75			return fmt.Errorf("workerstatus: create tmp: %w", err)
76		}
77		tmpName := tmp.Name()
78		if _, err := tmp.Write(data); err != nil {
79			_ = tmp.Close()
80			_ = os.Remove(tmpName)
81			return fmt.Errorf("workerstatus: write tmp: %w", err)
82		}
83		if err := tmp.Close(); err != nil {
84			_ = os.Remove(tmpName)
85			return fmt.Errorf("workerstatus: close tmp: %w", err)
86		}
87		if err := os.Rename(tmpName, final); err != nil {
88			_ = os.Remove(tmpName)
89			return fmt.Errorf("workerstatus: rename: %w", err)
90		}
91		return nil
92	}
93	
94	// ReadLiveness reads the sidecar for workerID under projectRoot.
95	func ReadLiveness(projectRoot, workerID string) (LivenessRecord, error) {
96		var rec LivenessRecord
97		data, err := os.ReadFile(LivenessPath(projectRoot, workerID))
98		if err != nil {
99			return rec, err
100		}
101		if err := json.Unmarshal(data, &rec); err != nil {
102			return rec, fmt.Errorf("workerstatus: parse liveness: %w", err)
103		}
104		return rec, nil
105	}
106	
107	// ListLiveness reads every status.json sidecar under projectRoot's worker
108	// directory. Malformed sidecars are skipped silently — the sidecar is
109	// best-effort observability, not authoritative state.
110	func ListLiveness(projectRoot string) ([]LivenessRecord, error) {
111		dir := LivenessDir(projectRoot)
112		entries, err := os.ReadDir(dir)
113		if err != nil {
114			if os.IsNotExist(err) {
115				return nil, nil
116			}
117			return nil, err
118		}
119		var out []LivenessRecord
120		for _, entry := range entries {
121			if !entry.IsDir() {
122				continue
123			}
124			rec, err := ReadLiveness(projectRoot, entry.Name())
125			if err != nil {
126				continue
127			}
128			out = append(out, rec)
129		}
130		sort.Slice(out, func(i, j int) bool {
131			return out[i].LastActivityAt.After(out[j].LastActivityAt)
132		})
133		return out, nil
134	}
135	
136	// IsFresh reports whether rec.LastActivityAt is within LivenessTTL of now.
137	func (r LivenessRecord) IsFresh(now time.Time) bool {
138		if r.LastActivityAt.IsZero() {
139			return false
140		}
141		return now.Sub(r.LastActivityAt) <= LivenessTTL
142	}
