3	import "time"
4	
5	const livenessStartedAtSkew = 10 * time.Second
6	
7	// EnrichWithFreshLiveness overlays fresh worker sidecars onto live process
8	// rows. The process scan remains authoritative for liveness, pid, command,
9	// and project scope; the sidecar only fills execution-specific fields that a
10	// long-running `ddx work --watch` parent does not carry in argv/cwd.
11	func EnrichWithFreshLiveness(workers []LiveWorker, now time.Time) []LiveWorker {
12		if len(workers) == 0 {
13			return workers
14		}
15	
16		freshByProject := make(map[string]map[int][]LivenessRecord)
17		for _, w := range workers {
18			key := canonicalPath(w.ProjectRoot)
19			if key == "" {
20				continue
21			}
22			if _, ok := freshByProject[key]; ok {
23				continue
24			}
25			freshByProject[key] = freshLivenessByPID(key, now)
26		}
27	
28		out := make([]LiveWorker, len(workers))
29		copy(out, workers)
30		for i := range out {
31			projectKey := canonicalPath(out[i].ProjectRoot)
32			if projectKey == "" || out[i].PID <= 0 {
33				continue
34			}
35			rec, ok := matchingLivenessRecord(out[i], freshByProject[projectKey][out[i].PID])
36			if !ok {
37				continue
38			}
39			applyLivenessRecord(&out[i], rec)
40		}
41		return out
42	}
43	
44	func freshLivenessByPID(projectRoot string, now time.Time) map[int][]LivenessRecord {
45		records, err := ListLiveness(projectRoot)
46		if err != nil {
47			return nil
48		}
49		out := make(map[int][]LivenessRecord)
50		for _, rec := range records {
51			if rec.PID <= 0 || !rec.IsFresh(now) {
52				continue
53			}
54			out[rec.PID] = append(out[rec.PID], rec)
55		}
56		return out
57	}
58	
59	func matchingLivenessRecord(worker LiveWorker, records []LivenessRecord) (LivenessRecord, bool) {
60		if len(records) == 0 {
61			return LivenessRecord{}, false
62		}
63		// records are already filtered to fresh sidecars for this worker's project
64		// root and PID. A single fresh same-PID sidecar is authoritative: PID +
65		// freshness is sufficient, so a start-time skew between the process
66		// scanner's reported start time and the sidecar's recorded started_at must
67		// not discard it (ddx-f9b41107). The start-time check only disambiguates a
68		// reused PID — i.e. when more than one fresh sidecar claims the same PID.
69		if len(records) == 1 {
70			return records[0], true
71		}
72		for _, rec := range records {
73			if startedAtCompatible(worker.StartedAt, rec.StartedAt) {
74				return rec, true
75			}
76		}
77		// Multiple fresh same-PID sidecars but none start-time-compatible: surface
78		// the most recently active one rather than nothing.
79		best := records[0]
80		for _, rec := range records[1:] {
81			if rec.LastActivityAt.After(best.LastActivityAt) {
82				best = rec
83			}
84		}
85		return best, true
86	}
87	
88	func startedAtCompatible(workerStartedAt, sidecarStartedAt time.Time) bool {
89		if workerStartedAt.IsZero() || sidecarStartedAt.IsZero() {
90			return true
91		}
92		delta := workerStartedAt.Sub(sidecarStartedAt)
93		if delta < 0 {
94			delta = -delta
95		}
96		return delta <= livenessStartedAtSkew
97	}
98	
99	func applyLivenessRecord(worker *LiveWorker, rec LivenessRecord) {
100		if worker == nil {
101			return
102		}
103		if worker.BeadID == "" && rec.CurrentBead != "" {
104			worker.BeadID = rec.CurrentBead
105		}
106		if worker.AttemptID == "" && rec.AttemptID != "" {
107			worker.AttemptID = rec.AttemptID
108		}
109		if worker.Phase == "" && rec.Phase != "" {
110			worker.Phase = rec.Phase
111		}
112		if worker.Message == "" && rec.Message != "" {
113			worker.Message = rec.Message
114		}
115		if worker.ChildPID == 0 && rec.ChildPID > 0 {
116			worker.ChildPID = rec.ChildPID
117		}
118		if worker.LastActivityAt.IsZero() && !rec.LastActivityAt.IsZero() {
119			worker.LastActivityAt = rec.LastActivityAt.UTC()
120		}
121		if worker.ExecutionWorktree == "" && rec.ChildPID > 0 {
122			childBead, childWorktree := inferExecutionFromPID(rec.ChildPID)
123			if childWorktree != "" {
124				worker.ExecutionWorktree = childWorktree
125			}
126			if worker.BeadID == "" && childBead != "" {
127				worker.BeadID = childBead
128			}
129		}
130	}
