253	func clockTicksPerSecond() float64 {
254		// Linux exposes CLK_TCK as a sysconf value; the kernel default on
255		// every platform DDx supports is 100. Using the constant keeps us
256		// free of cgo without changing the calculated age in practice.
257		return 100.0
258	}
