package agent

// provider_children.go gives a worker attempt ownership over the provider CLI
// subprocesses (claude, codex, gemini, ...) that Fizeau spawns underneath it.
//
// PROBLEM (ddx-c02ce93c): a single `ddx work` attempt could leave unrelated
// provider CLIs resident — e.g. a `codex` and a `gemini` child lingering while
// the active route was `claude/sonnet`. Those strays burn resources, make
// process status ambiguous, and orphan to PID 1 on worker exit. DDx must
// therefore (a) reap any provider child not owned by the active route, and
// (b) reap every provider child when the attempt ends, recording durable
// evidence for each kill — independent of whether Fizeau cleaned up.
//
// The scanner is injectable (providerChildScanner) so regression tests drive
// classification and reaping against fake long-lived child processes rather
// than real provider CLIs.

import (
	"context"
	"path/filepath"
	"strings"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/workerstatus"
)

// Evidence constants stamped on reaped provider children.
const (
	providerChildActionTerminated = "terminated"
	reasonSupersededProviderChild = "superseded_provider_child"
	reasonAttemptEnded            = "attempt_ended"
	providerChildCleanupArtifact  = "provider-children.json"
)

// providerCLINames are the harness/provider CLI basenames a worker attempt
// owns. Mirrors looksLikeHarnessProcess; kept as a set for O(1) lookup.
var providerCLINames = map[string]struct{}{
	"claude":   {},
	"codex":    {},
	"gemini":   {},
	"opencode": {},
	"pi":       {},
}

// providerForCommand returns the provider CLI name (argv[0] basename) when
// cmdline launches a known provider CLI, else "".
func providerForCommand(cmdline string) string {
	parts := strings.Fields(strings.TrimSpace(cmdline))
	if len(parts) == 0 {
		return ""
	}
	base := filepath.Base(parts[0])
	if _, ok := providerCLINames[base]; ok {
		return base
	}
	return ""
}

// providerChildProcess is a raw provider CLI subprocess observed under the
// worker process tree, before route classification.
type providerChildProcess struct {
	PID       int
	Provider  string
	Command   string
	StartedAt time.Time
}

// providerChildReapRecord is the durable, per-child evidence of a reap.
type providerChildReapRecord struct {
	PID        int     `json:"pid"`
	Provider   string  `json:"provider"`
	Command    string  `json:"command,omitempty"`
	AgeSeconds float64 `json:"age_seconds"`
	Action     string  `json:"action"`
	Reason     string  `json:"reason"`
}

// providerChildCleanupReport is the artifact written to the per-attempt bundle
// recording which provider children were reaped and why.
type providerChildCleanupReport struct {
	AttemptID  string                    `json:"attempt_id"`
	BeadID     string                    `json:"bead_id"`
	Trigger    string                    `json:"trigger"`
	ActiveRoute string                   `json:"active_route,omitempty"`
	ScannedAt  time.Time                 `json:"scanned_at"`
	Survivors  []workerstatus.ProviderChild `json:"survivors,omitempty"`
	Reaped     []providerChildReapRecord `json:"reaped,omitempty"`
	ScanErr    string                    `json:"scan_error,omitempty"`
}

// providerChildScanner enumerates provider CLI descendants of rootPID. It is a
// package var so tests can inject a deterministic process set. The default is
// the platform scanner (scanProviderChildProcessesImpl).
var providerChildScanner = func(ctx context.Context, rootPID int, now time.Time) ([]providerChildProcess, error) {
	return scanProviderChildProcessesImpl(ctx, rootPID, now)
}

// terminateProviderChild kills a provider child's process group (SIGTERM, brief
// grace, then SIGKILL). Package var so tests can observe/override termination.
var terminateProviderChild = terminateProviderChildImpl

// normalizeProviderToken lowercases and trims a routing token for comparison.
func normalizeProviderToken(s string) string {
	return strings.ToLower(strings.TrimSpace(s))
}

// routeOwnsProvider reports whether the active route (its provider/harness/route
// label) legitimately owns a child running the given provider CLI. The match is
// by provider name appearing as a token of the route identity, so route
// "claude/sonnet" owns a `claude` child but not a `codex` or `gemini` child.
func routeOwnsProvider(provider string, routeTokens ...string) bool {
	p := normalizeProviderToken(provider)
	if p == "" {
		return false
	}
	for _, tok := range routeTokens {
		tok = normalizeProviderToken(tok)
		if tok == "" {
			continue
		}
		if tok == p {
			return true
		}
		// route labels are commonly "provider/model"; match the leading segment.
		if seg := strings.SplitN(tok, "/", 2); len(seg) > 0 && seg[0] == p {
			return true
		}
	}
	return false
}

// scanProviderChildrenForStatus returns the live provider children under
// rootPID classified against the active route, shaped for the worker-status
// sidecar. routeLabel/harness identify the active route; phase is stamped on
// each child. A child owned by the active route carries RouteOwner; an
// unrelated (superseded) child carries an empty RouteOwner.
func scanProviderChildrenForStatus(ctx context.Context, rootPID int, routeLabel, harness, phase string, now time.Time) []workerstatus.ProviderChild {
	procs, err := providerChildScanner(ctx, rootPID, now)
	if err != nil || len(procs) == 0 {
		return nil
	}
	out := make([]workerstatus.ProviderChild, 0, len(procs))
	for _, proc := range procs {
		owner := ""
		if routeOwnsProvider(proc.Provider, routeLabel, harness) {
			owner = strings.TrimSpace(routeLabel)
			if owner == "" {
				owner = strings.TrimSpace(harness)
			}
		}
		out = append(out, workerstatus.ProviderChild{
			PID:        proc.PID,
			Provider:   proc.Provider,
			Harness:    proc.Provider,
			RouteOwner: owner,
			Phase:      phase,
			AgeSeconds: childAgeSeconds(proc, now),
		})
	}
	return out
}

// reapProviderChildren scans provider CLI descendants of rootPID and terminates
// each child for which reasonFor returns a non-empty reason. It returns the
// evidence records (one per reaped child) plus the survivors. now provides age.
func reapProviderChildren(ctx context.Context, rootPID int, now time.Time, reasonFor func(providerChildProcess) string) ([]providerChildReapRecord, []workerstatus.ProviderChild, error) {
	procs, err := providerChildScanner(ctx, rootPID, now)
	if err != nil {
		return nil, nil, err
	}
	var reaped []providerChildReapRecord
	var survivors []workerstatus.ProviderChild
	for _, proc := range procs {
		reason := reasonFor(proc)
		if reason == "" {
			survivors = append(survivors, workerstatus.ProviderChild{
				PID:        proc.PID,
				Provider:   proc.Provider,
				Harness:    proc.Provider,
				AgeSeconds: childAgeSeconds(proc, now),
			})
			continue
		}
		terminateProviderChild(proc.PID)
		reaped = append(reaped, providerChildReapRecord{
			PID:        proc.PID,
			Provider:   proc.Provider,
			Command:    proc.Command,
			AgeSeconds: childAgeSeconds(proc, now),
			Action:     providerChildActionTerminated,
			Reason:     reason,
		})
	}
	return reaped, survivors, nil
}

// reapSupersededProviderChildren reaps provider children not owned by the
// active route. Called once a route resolves so a single attempt never retains
// unrelated provider CLIs alongside its active route.
func reapSupersededProviderChildren(ctx context.Context, rootPID int, routeLabel, harness string, now time.Time) ([]providerChildReapRecord, []workerstatus.ProviderChild) {
	reaped, survivors, err := reapProviderChildren(ctx, rootPID, now, func(proc providerChildProcess) string {
		if routeOwnsProvider(proc.Provider, routeLabel, harness) {
			return ""
		}
		return reasonSupersededProviderChild
	})
	if err != nil {
		return nil, nil
	}
	return reaped, survivors
}

// reapAllProviderChildren reaps every provider child under rootPID. Called at
// attempt end (success, failure, or interruption) so no provider CLI outlives
// the attempt.
func reapAllProviderChildren(ctx context.Context, rootPID int, now time.Time) []providerChildReapRecord {
	reaped, _, err := reapProviderChildren(ctx, rootPID, now, func(providerChildProcess) string {
		return reasonAttemptEnded
	})
	if err != nil {
		return nil
	}
	return reaped
}

func childAgeSeconds(proc providerChildProcess, now time.Time) float64 {
	if proc.StartedAt.IsZero() {
		return 0
	}
	age := now.Sub(proc.StartedAt)
	if age < 0 {
		return 0
	}
	return age.Seconds()
}

// writeProviderChildCleanupArtifact persists the cleanup report under the
// per-attempt bundle. Best-effort; never fails the attempt.
func writeProviderChildCleanupArtifact(projectRoot, attemptID string, report *providerChildCleanupReport) {
	if report == nil || strings.TrimSpace(projectRoot) == "" || strings.TrimSpace(attemptID) == "" {
		return
	}
	path := filepath.Join(projectRoot, ExecuteBeadArtifactDir, attemptID, providerChildCleanupArtifact)
	_ = writeArtifactJSON(path, report)
}

//go:build !windows

package agent

import (
	"bytes"
	"context"
	"os"
	"os/exec"
	"strconv"
	"strings"
	"syscall"
	"time"
)

// scanProviderChildProcessesImpl enumerates provider CLI subprocesses that are
// descendants of rootPID. It reads the process table once via `ps`, walks the
// ppid tree from rootPID, and keeps the entries whose argv[0] basename is a
// known provider CLI. rootPID itself and the scanning process are excluded so a
// worker never reaps itself.
func scanProviderChildProcessesImpl(ctx context.Context, rootPID int, now time.Time) ([]providerChildProcess, error) {
	cmd := exec.CommandContext(ctx, "ps", "-axo", "pid=,ppid=,etime=,command=")
	out, err := cmd.Output()
	if err != nil {
		return nil, err
	}
	rows := parseProviderPS(out)

	children := map[int][]int{}
	row := map[int]providerPSRow{}
	for _, r := range rows {
		row[r.PID] = r
		children[r.PPID] = append(children[r.PPID], r.PID)
	}

	self := os.Getpid()
	descendants := collectDescendants(children, rootPID)

	out2 := make([]providerChildProcess, 0)
	for pid := range descendants {
		if pid == rootPID || pid == self || pid <= 0 {
			continue
		}
		r, ok := row[pid]
		if !ok {
			continue
		}
		provider := providerForCommand(r.Command)
		if provider == "" {
			continue
		}
		started := time.Time{}
		if r.ElapsedSeconds >= 0 {
			started = now.Add(-time.Duration(r.ElapsedSeconds) * time.Second)
		}
		out2 = append(out2, providerChildProcess{
			PID:       pid,
			Provider:  provider,
			Command:   r.Command,
			StartedAt: started,
		})
	}
	return out2, nil
}

type providerPSRow struct {
	PID            int
	PPID           int
	ElapsedSeconds int64 // -1 when unparsable
	Command        string
}

func parseProviderPS(out []byte) []providerPSRow {
	lines := bytes.Split(out, []byte{'\n'})
	rows := make([]providerPSRow, 0, len(lines))
	for _, line := range lines {
		fields := strings.Fields(string(line))
		if len(fields) < 4 {
			continue
		}
		pid, pidErr := strconv.Atoi(fields[0])
		ppid, ppidErr := strconv.Atoi(fields[1])
		if pidErr != nil || ppidErr != nil {
			continue
		}
		rows = append(rows, providerPSRow{
			PID:            pid,
			PPID:           ppid,
			ElapsedSeconds: parseEtime(fields[2]),
			Command:        strings.Join(fields[3:], " "),
		})
	}
	return rows
}

// parseEtime parses POSIX `ps` etime ([[DD-]hh:]mm:ss) into seconds. Returns -1
// when the value cannot be parsed.
func parseEtime(s string) int64 {
	s = strings.TrimSpace(s)
	if s == "" {
		return -1
	}
	var days int64
	if i := strings.Index(s, "-"); i >= 0 {
		d, err := strconv.ParseInt(s[:i], 10, 64)
		if err != nil {
			return -1
		}
		days = d
		s = s[i+1:]
	}
	parts := strings.Split(s, ":")
	var h, m, sec int64
	var err error
	switch len(parts) {
	case 3:
		if h, err = strconv.ParseInt(parts[0], 10, 64); err != nil {
			return -1
		}
		if m, err = strconv.ParseInt(parts[1], 10, 64); err != nil {
			return -1
		}
		if sec, err = strconv.ParseInt(parts[2], 10, 64); err != nil {
			return -1
		}
	case 2:
		if m, err = strconv.ParseInt(parts[0], 10, 64); err != nil {
			return -1
		}
		if sec, err = strconv.ParseInt(parts[1], 10, 64); err != nil {
			return -1
		}
	default:
		return -1
	}
	return days*86400 + h*3600 + m*60 + sec
}

func collectDescendants(children map[int][]int, root int) map[int]struct{} {
	out := map[int]struct{}{}
	queue := []int{root}
	for len(queue) > 0 {
		pid := queue[0]
		queue = queue[1:]
		for _, child := range children[pid] {
			if _, seen := out[child]; seen {
				continue
			}
			out[child] = struct{}{}
			queue = append(queue, child)
		}
	}
	return out
}

// terminateProviderChildImpl terminates a provider child's process group with a
// graceful SIGTERM, a brief grace window, then SIGKILL. Provider CLIs are
// spawned in their own process group (Setpgid), so the negative-pid signal
// reaps the child and any of its own descendants.
func terminateProviderChildImpl(pid int) {
	if pid <= 0 || pid == os.Getpid() {
		return
	}
	signalProviderChildGroup(pid, syscall.SIGTERM)
	deadline := time.Now().Add(750 * time.Millisecond)
	for time.Now().Before(deadline) {
		if !signalProcessAlive(pid) {
			return
		}
		time.Sleep(25 * time.Millisecond)
	}
	signalProviderChildGroup(pid, syscall.SIGKILL)
}

// signalProviderChildGroup signals the child's process group, falling back to
// the bare pid when the child is not a group leader.
func signalProviderChildGroup(pid int, sig syscall.Signal) {
	if err := syscall.Kill(-pid, sig); err != nil && err != syscall.ESRCH {
		_ = syscall.Kill(pid, sig)
	}
}

