)

// startFakeProviderChild spawns a long-lived process whose argv[0] basename is
// provider (claude/codex/gemini). It is a real child of the test process — so
// the descendant scan finds it — but lives in its own process group so reaping
// it via the negative-pid signal never touches the test runner.
func startFakeProviderChild(t *testing.T, dir, provider string) int {
	t.Helper()
	sleepPath, err := exec.LookPath("sleep")
	if err != nil {
		t.Skipf("sleep not available: %v", err)
	}
	bin := filepath.Join(dir, provider)
	if err := os.Symlink(sleepPath, bin); err != nil {
		t.Fatalf("symlink fake %s: %v", provider, err)
	}
	cmd := exec.Command(bin, "120")
	cmd.SysProcAttr = &syscall.SysProcAttr{Setpgid: true}
	if err := cmd.Start(); err != nil {
		t.Fatalf("start fake %s: %v", provider, err)
	}
	pid := cmd.Process.Pid
	go func() { _, _ = cmd.Process.Wait() }()
	t.Cleanup(func() {
		_ = syscall.Kill(-pid, syscall.SIGKILL)
	})
	return pid
}

// TestAttemptProviderChildrenAreRouteScoped proves that after an active route
// is selected, only provider children belonging to that route remain alive:
// fake codex and gemini children are reaped while the claude child the route
// owns survives. (ddx-c02ce93c AC1)
func TestAttemptProviderChildrenAreRouteScoped(t *testing.T) {
	dir := t.TempDir()
	claudePID := startFakeProviderChild(t, dir, "claude")
	codexPID := startFakeProviderChild(t, dir, "codex")
	geminiPID := startFakeProviderChild(t, dir, "gemini")

	// Wait for all three to be visible to the scanner.
	waitForProviderChildren(t, os.Getpid(), claudePID, codexPID, geminiPID)

	reaped, survivors := reapSupersededProviderChildren(context.Background(), os.Getpid(), "claude/sonnet", "", time.Now().UTC())

	assertProcessGone(t, codexPID)
	assertProcessGone(t, geminiPID)
	if !signalProcessAlive(claudePID) {
		t.Fatalf("active-route claude child %d was reaped; it must survive", claudePID)
	}

	reapedProviders := map[string]bool{}
	for _, r := range reaped {
		reapedProviders[r.Provider] = true
	}
	if !reapedProviders["codex"] || !reapedProviders["gemini"] {
		t.Fatalf("expected codex and gemini reaped; got %+v", reaped)
	}
	if reapedProviders["claude"] {
		t.Fatalf("claude must not be reaped; got %+v", reaped)
	}
	var sawClaude bool
	for _, s := range survivors {
		if s.Provider == "claude" {
			sawClaude = true
		}
		if s.Provider == "codex" || s.Provider == "gemini" {
			t.Fatalf("survivor list must not contain superseded provider %s", s.Provider)
		}
	}
	if !sawClaude {
		t.Fatalf("claude must be reported as a surviving route-scoped child; got %+v", survivors)
	}
}

// TestSupersededProviderChildrenAreReapedWithEvidence proves a route/probe
// child that outlives route selection is terminated and recorded with pid,
// provider, age, action=terminated, and reason=superseded_provider_child.
// (ddx-c02ce93c AC2)
func TestSupersededProviderChildrenAreReapedWithEvidence(t *testing.T) {
	now := time.Now().UTC()
	const supersededPID = 424242
	restoreScanner := providerChildScanner
	restoreTerminate := terminateProviderChild
	t.Cleanup(func() {
		providerChildScanner = restoreScanner
		terminateProviderChild = restoreTerminate
	})

	providerChildScanner = func(context.Context, int, time.Time) ([]providerChildProcess, error) {
		return []providerChildProcess{{
			PID:       supersededPID,
			Provider:  "codex",
			Command:   "/usr/local/bin/codex --no-alt-screen",
			StartedAt: now.Add(-90 * time.Second),
		}}, nil
	}
	var mu sync.Mutex
	var killed []int
	terminateProviderChild = func(pid int) {
		mu.Lock()
		killed = append(killed, pid)
		mu.Unlock()
	}

	reaped, survivors := reapSupersededProviderChildren(context.Background(), os.Getpid(), "claude/sonnet", "", now)

	if len(survivors) != 0 {
		t.Fatalf("expected no survivors; got %+v", survivors)
	}
	if len(reaped) != 1 {
		t.Fatalf("expected exactly one reaped record; got %+v", reaped)
	}
	rec := reaped[0]
	if rec.PID != supersededPID {
		t.Errorf("evidence pid = %d, want %d", rec.PID, supersededPID)
	}
	if rec.Provider != "codex" {
		t.Errorf("evidence provider = %q, want codex", rec.Provider)
	}
	if rec.Action != providerChildActionTerminated {
		t.Errorf("evidence action = %q, want %q", rec.Action, providerChildActionTerminated)
	}
	if rec.Reason != reasonSupersededProviderChild {
		t.Errorf("evidence reason = %q, want %q", rec.Reason, reasonSupersededProviderChild)
	}
	if rec.AgeSeconds < 89 || rec.AgeSeconds > 91 {
		t.Errorf("evidence age_seconds = %v, want ~90", rec.AgeSeconds)
	}
	mu.Lock()
	defer mu.Unlock()
	if len(killed) != 1 || killed[0] != supersededPID {
		t.Fatalf("expected terminate called once for pid %d; got %v", supersededPID, killed)
	}
}

// TestAttemptEndReapsAllProviderChildren proves that successful, failed, and
// interrupted attempts each leave no provider child process under the worker
// process tree. (ddx-c02ce93c AC4)
func TestAttemptEndReapsAllProviderChildren(t *testing.T) {
	for _, mode := range []string{"success", "failure", "interrupt"} {
		t.Run(mode, func(t *testing.T) {
			beadID := "ddx-provider-end-" + mode
			projectRoot, gitOps := setupProcessCleanupAttempt(t, beadID)
			binDir := t.TempDir()
			runner := newProviderChildRunner(t, binDir, "codex", mode)

			ctx := context.Background()
			var cancel context.CancelFunc
			if mode == "interrupt" {
				ctx, cancel = context.WithCancel(ctx)
			}

			done := make(chan struct{})
			go func() {
				_, _ = ExecuteBeadWithConfig(ctx, projectRoot, beadID, processCleanupConfig(), ExecuteBeadRuntime{
					AgentRunner: runner,
				}, gitOps)
				close(done)
			}()

			pid := <-runner.started
			if mode == "interrupt" {
				cancel()
			}
			select {
			case <-done:
			case <-time.After(10 * time.Second):
				t.Fatal("ExecuteBeadWithConfig did not return")
			}
			assertProcessGone(t, pid)
		})
	}
}

// providerChildRunner is an AgentRunner stub that spawns a provider-named child
// (in its own process group, outside the worktree) during dispatch, then
// returns according to mode.
type providerChildRunner struct {
	bin     string
	started chan int
	mode    string
}

func newProviderChildRunner(t *testing.T, dir, provider, mode string) *providerChildRunner {
	t.Helper()
	sleepPath, err := exec.LookPath("sleep")
	if err != nil {
		t.Skipf("sleep not available: %v", err)
	}
	bin := filepath.Join(dir, provider)
	if err := os.Symlink(sleepPath, bin); err != nil {
		t.Fatalf("symlink fake %s: %v", provider, err)
	}
	return &providerChildRunner{bin: bin, started: make(chan int, 1), mode: mode}
}

func (r *providerChildRunner) Run(opts RunArgs) (*Result, error) {
	cmd := exec.Command(r.bin, "120")
	cmd.SysProcAttr = &syscall.SysProcAttr{Setpgid: true}
	if err := cmd.Start(); err != nil {
		return &Result{ExitCode: 1, Error: err.Error()}, nil
	}
	pid := cmd.Process.Pid
	go func() { _, _ = cmd.Process.Wait() }()
	r.started <- pid
	switch r.mode {
	case "interrupt":
		ctx := opts.Context
		if ctx == nil {
			ctx = context.Background()
		}
		<-ctx.Done()
		return &Result{ExitCode: 1, Error: ctx.Err().Error()}, nil
	case "failure":
		return &Result{ExitCode: 1, Error: "synthetic failure"}, nil
	default:
		return &Result{ExitCode: 0}, nil
	}
}

// waitForProviderChildren blocks until the real scanner observes every pid as a
// provider child of rootPID, so route-scoping assertions are not racy against
// process startup.
func waitForProviderChildren(t *testing.T, rootPID int, pids ...int) {
	t.Helper()
	deadline := time.Now().Add(3 * time.Second)
	for time.Now().Before(deadline) {
		procs, err := providerChildScanner(context.Background(), rootPID, time.Now().UTC())
		if err == nil {
			seen := map[int]bool{}
			for _, p := range procs {
				seen[p.PID] = true
			}
			all := true
			for _, pid := range pids {
				if !seen[pid] {
					all = false
					break
				}
			}
			if all {
				return
			}
		}
		time.Sleep(25 * time.Millisecond)
	}
	t.Fatalf("scanner did not observe all provider children %v under pid %d", pids, rootPID)
}

